#include <iostream>\n#include \"../classes/Gestion.h\"\n#include <cstring>\n\nusing namespace std;\n\nvoid mostrarMenu() {\n    cout << \"\\n========================================\" << endl;\n    cout << \"     REPRODUCTOR MUSICAL - TALLER 2\" << endl;\n    cout << \"========================================\" << endl;\n    cout << \"1. Ver todas las canciones\" << endl;\n    cout << \"2. Buscar cancion por nombre\" << endl;\n    cout << \"3. Ver Top 10 canciones\" << endl;\n    cout << \"4. Reproducir cancion\" << endl;\n    cout << \"5. Cargar canciones desde archivo\" << endl;\n    cout << \"6. Guardar canciones en archivo\" << endl;\n    cout << \"0. Salir\" << endl;\n    cout << \"Seleccione una opcion: \";\n}\n\nint main() {\n    Gestion gestion;\n    int opcion;\n    char buffer[256];\n\n    gestion.cargarCancionesDesdeArchivo(\"../data/music_source.txt\");\n\n    while (true) {\n        mostrarMenu();\n        cin >> opcion;\n        cin.ignore();\n\n        switch (opcion) {\n            case 1:\n                gestion.mostrarTodasLasCanciones();\n                break;\n\n            case 2: {\n                cout << \"Ingrese el nombre o parte de la cancion a buscar: \";\n                cin.getline(buffer, sizeof(buffer));\n                gestion.buscarCancion(buffer);\n                break;\n            }\n\n            case 3:\n                gestion.mostrarTop10();\n                break;\n\n            case 4: {\n                cout << \"Ingrese el ID de la cancion a reproducir: \";\n                int id;\n                cin >> id;\n                gestion.reproducirCancion(id);\n                break;\n            }\n\n            case 5: {\n                cout << \"Ingrese la ruta del archivo: \";\n                cin.getline(buffer, sizeof(buffer));\n                gestion.cargarCancionesDesdeArchivo(buffer);\n                break;\n            }\n\n            case 6: {\n                cout << \"Ingrese la ruta del archivo de destino: \";\n                cin.getline(buffer, sizeof(buffer));\n                gestion.guardarCancionesEnArchivo(buffer);\n                break;\n            }\n\n            case 0:\n                cout << \"Hasta luego!\" << endl;\n                return 0;\n\n            default:\n                cout << \"Opcion invalida. Intente de nuevo.\" << endl;\n        }\n    }\n\n    return 0;\n}\n"